Identity identity = context.getObjectByName(Identity.class,"Abdul samad");
QueryOptions qo=new QueryOptions();
Filter f1=Filter.and(Filter.eq("application.name","SCIMApp"),Filter.eq("identity.id",identity.getId()));
qo.add(f1);

List linkNames = new ArrayList();
//List links = context.getObjects(Link.class,qo);

List links = context.getObjects(Application.class);

if(links!=null){
  linkNames =ObjectUtil.getObjectNames(links);
   log.error("linkNames : "+linkNames);
}

log.error("linkNames : "+linkNames);
return linkNames;

Identity identity=context.getObjectByName(Identity.class,"Pat cummins");

ProvisioningPlan plan=new ProvisioningPlan();
plan.setIdentity(identity);
AccountRequest accReq=new AccountRequest(ProvisioningPlan.AccountRequest.Operation.Create,"ActiveDirectory",null,null);
plan.add(accReq);

Provisioner pr=new  Provisioner(context);
return pr.compile(plan).toXml();




